package com.example.orders.controller;

import com.example.orders.model.Order;
import com.example.orders.service.OrderService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.*;

import jakarta.validation.constraints.Positive;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@RestController
@RequestMapping("/api/orders")
public class OrderController {

    private static final Logger logger = LoggerFactory.getLogger(OrderController.class);

    private final OrderService orderService;

    public OrderController(OrderService orderService) {
        this.orderService = orderService;
    }

    @GetMapping("/{orderId}")
    public ResponseEntity<Order> getOrderById(@PathVariable @Positive Long orderId) {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();

        if (authentication == null || !authentication.isAuthenticated()) {
            logger.warn("Unauthenticated access attempt for order ID: {}", orderId);
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        }

        String authenticatedUsername = authentication.getName();

        Order order = orderService.findById(orderId);

        if (order == null) {
            logger.info("Order not found for ID: {} requested by user: {}", orderId, authenticatedUsername);
            return ResponseEntity.notFound().build();
        }

        // Authorization check: ensure the authenticated user owns this order
        if (!order.getUsername().equals(authenticatedUsername)) {
            logger.warn("User '{}' attempted to access order ID: {} belonging to another user", authenticatedUsername, orderId);
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }

        logger.info("Order ID: {} retrieved successfully by user: {}", orderId, authenticatedUsername);
        return ResponseEntity.ok(order);
    }
}